import {
  CHAPTER_BASED_TRIVIA_BOOK_CONFIG,
  getTriviaProgressBookKey,
} from "@/lib/triviaCatalog";

export type TriviaOption = {
  label: string;
  text: string;
};

export type TriviaQuestion = {
  id: string;
  question: string;
  options: TriviaOption[];
  correctAnswer: string;
  verse: string;
  explanation: string;
};

export type TriviaChapterPack = {
  chapter: number;
  title: string;
  description: string;
  progressKey: string;
  questions: TriviaQuestion[];
};

export type TriviaBookPack = {
  key: string;
  routeSlug: string;
  name: string;
  chapters: TriviaChapterPack[];
};

const OPTION_LABELS = ["A", "B", "C", "D"] as const;

function createQuestion(
  id: string,
  question: string,
  options: [string, string, string, string],
  correctAnswer: "A" | "B" | "C" | "D",
  verse: string,
  explanation: string,
): TriviaQuestion {
  return {
    id,
    question,
    options: options.map((text, index) => ({
      label: OPTION_LABELS[index],
      text,
    })),
    correctAnswer,
    verse,
    explanation,
  };
}

function createChapter(bookKey: string, chapter: number, description: string, questions: TriviaQuestion[]): TriviaChapterPack {
  return {
    chapter,
    title: `Chapter ${chapter}`,
    description,
    progressKey: getTriviaProgressBookKey(bookKey, chapter),
    questions,
  };
}

